# NOT idempotent
def send_payment_notification(payment_id):
    send_email(f"Payment {payment_id} processed")

# Idempotent
def send_payment_notification(payment_id):
    # Check if already sent
    if already_sent(payment_id):
        return "Already sent"

    send_email(f"Payment {payment_id} processed")
    mark_sent(payment_id)
